function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

const row = $json;
const status = safeStr(row.status);
const visualStatus = safeStr(row.visualStatus);

// Werte, die status/visualStatus in P6 (Bildgenerierung) annehmen koennen -
// dort ueberschreiben beide Spalten sich gegenseitig mit denselben Werten,
// das ist die "dritte Achse" (Bild-Stufe), keine echte Content- oder Visual-Stufe mehr.
const IMAGE_VALUES = new Set([
  'image_composed', 'nextcloud_upload_failed', 'image_retrying', 'retry_required',
  'image_qa_error', 'image_quality_failed', 'image_qa_approved', 'visual_concept_repairing',
  'visual_concept_repair_failed', 'visual_prompt_ready', 'visual_topic_error_final',
  'blocked_by_source_lock', 'image_qa_rechecking', 'force_image_refresh', 'force_image_reset',
  'force_full_image_refresh', 'visual_prompt_failed_final', 'image_prompt_ready',
  'image_retry_required', 'image_qa_retry_required', 'raw_generated', 'ready_for_composite'
]);

const CONTENT_ERROR = new Set([
  'detail_failed', 'metadata_error', 'analysis_error', 'summary_input_error',
  'summary_parse_error', 'content_error'
]);

const CONTENT_DIRECT = {
  '': 'new',
  'needs_summary': 'needs_summary',
  'watching': 'watching',
  'ignored': 'ignored',
  'needs_content': 'needs_content',
  'content_generated': 'content_generated',
  'content_posted': 'content_posted',
  'nextcloud_failed': 'needs_summary',
  'nextcloud_failed_final': 'archiving_failed',
  'nextcloud_archived': 'needs_summary'
};

let contentStage;
let contentErrorReason = '';
if (CONTENT_ERROR.has(status)) {
  contentStage = 'error';
  contentErrorReason = status;
} else if (Object.prototype.hasOwnProperty.call(CONTENT_DIRECT, status)) {
  contentStage = CONTENT_DIRECT[status];
} else if (IMAGE_VALUES.has(status)) {
  // status wurde von P6 ueberschrieben - Content muss zu diesem Zeitpunkt laengst fertig sein.
  contentStage = (row.wordpressPosted === 'true' || row.wordpressPosted === true) ? 'content_posted' : 'content_generated';
} else {
  contentStage = 'unknown';
}

const VISUAL_DIRECT = {
  'no_visual': 'not_applicable',
  'visual_topic_ok': 'topic_ok',
  'visual_topic_error': 'topic_error',
  'blocked_by_content_error': 'blocked_content_error',
  'blocked_by_source_lock': 'blocked_source_lock',
  'waiting_for_content': 'waiting_for_content',
  'needs_visual_prompt': 'needs_prompt',
  'visual_prompt_ready': 'prompt_ready',
  'visual_prompt_error': 'prompt_error',
  'visual_prompt_topic_error': 'prompt_error',
  'awaiting_headline_choice': 'awaiting_headline_choice',
  'headline_selected': 'headline_selected',
  'force_visual_reset': 'needs_prompt',
  'visual_prompt_failed_final': 'prompt_failed_final'
};

let visualStage;
if (Object.prototype.hasOwnProperty.call(VISUAL_DIRECT, visualStatus)) {
  visualStage = VISUAL_DIRECT[visualStatus];
} else if (IMAGE_VALUES.has(visualStatus)) {
  // visualStatus wurde von P6 ueberschrieben - Prompt-Phase muss abgeschlossen sein.
  visualStage = 'prompt_ready';
} else if (visualStatus === '') {
  visualStage = 'not_applicable';
} else {
  visualStage = 'unknown';
}

const IMAGE_DIRECT = {
  'raw_generated': 'raw_generated',
  'ready_for_composite': 'ready_for_composite',
  'image_composed': 'composed',
  'nextcloud_upload_failed': 'upload_failed',
  'image_retrying': 'qa_pending',
  'retry_required': 'qa_pending',
  'image_retry_required': 'qa_pending',
  'image_qa_error': 'qa_pending',
  'image_qa_retry_required': 'qa_pending',
  'image_qa_rechecking': 'qa_pending',
  'image_quality_failed': 'qa_failed',
  'image_qa_approved': 'qa_approved',
  'visual_concept_repairing': 'concept_repairing',
  'visual_concept_repair_failed': 'concept_repair_failed',
  'visual_topic_error_final': 'topic_error_final'
};

let imageStage = 'not_started';
if (Object.prototype.hasOwnProperty.call(IMAGE_DIRECT, visualStatus)) {
  imageStage = IMAGE_DIRECT[visualStatus];
} else if (Object.prototype.hasOwnProperty.call(IMAGE_DIRECT, status)) {
  imageStage = IMAGE_DIRECT[status];
} else if (safeStr(row.imageFinalPath)) {
  imageStage = 'composed';
}

return {
  json: {
    vorgangKey: row.vorgangKey,
    _rawStatus: status,
    _rawVisualStatus: visualStatus,
    contentStage: contentStage,
    contentErrorReason: contentErrorReason,
    visualStage: visualStage,
    imageStage: imageStage
  }
};
